insert into public.species_categories(name,slug) values('Snakes','snakes'),('Lizards','lizards'),('Turtles','turtles'),('Amphibians','amphibians'),('Invertebrates','invertebrates'),('Fish','fish'),('Birds','birds'),('Mammals','mammals') on conflict do nothing;
insert into public.article_categories(name,slug) values('Care Guide','care-guide'),('Husbandry','husbandry'),('Feeding','feeding'),('Health','health'),('Morph Guide','morph-guide'),('Breeding','breeding'),('Equipment','equipment'),('Beginner Guide','beginner-guide') on conflict do nothing;
