insert into public.species(category_id,common_name,scientific_name,slug,care_level,lifespan,adult_size,temperature,humidity,feeding,habitat,morph_information,status) select id,'Ball Python','Python regius','ball-python','Beginner','20–30 years','90–150 cm','26–33°C','60–80%','Appropriately sized rodents','Secure terrestrial vivarium','Thousands of color and pattern morphs','published' from public.species_categories where slug='snakes' on conflict do nothing;
